import pytest

def test_submit_valid_timesheet_happy_path(auth_client, unique_week):
    payload = {
        "week": unique_week,
        "days": {
            "mon": 8, "tue": 8, "wed": 8, "thu": 8, "fri": 8,
            "sat": 0, "sun": 0
        }
    }
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code in (200, 201), resp.text
    body = resp.json()
    assert body["state"] == "submitted"
    assert "id" in body

def test_submit_timesheet_per_day_hours_exceed_24(auth_client, unique_week):
    payload = {
        "week": unique_week,
        "days": {
            "mon": 8, "tue": 8, "wed": 25, "thu": 8, "fri": 8,
            "sat": 0, "sun": 0
        }
    }
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code == 422, resp.text
    body = resp.json()
    assert any("day" in str(e).lower() or "hours" in str(e).lower()
               for e in body.get("detail", [body]))

def test_submit_timesheet_weekly_total_boundary_at_80(auth_client, unique_week):
    payload = {
        "week": unique_week,
        "days": {
            "mon": 12, "tue": 12, "wed": 12, "thu": 12,
            "fri": 12, "sat": 12, "sun": 8
        }
    }
    total = sum(payload["days"].values())
    assert total == 80
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code in (200, 201), resp.text
    assert resp.json()["state"] == "submitted"

def test_submit_timesheet_weekly_total_exceeds_80(auth_client, unique_week):
    payload = {
        "week": unique_week,
        "days": {
            "mon": 12, "tue": 12, "wed": 12, "thu": 12,
