def test_submit_timesheet_state_transition_draft_to_submitted(
        auth_client, draft_timesheet):
    ts_id = draft_timesheet["id"]
    payload = {
        "week": draft_timesheet["week"],
        "days": {
            "mon": 8, "tue": 8, "wed": 8, "thu": 8, "fri": 8,
            "sat": 0, "sun": 0
        }
    }
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code in (200, 201), resp.text
    get_resp = auth_client.get(f"/timesheets/{ts_id}")
    assert get_resp.status_code == 200
    assert get_resp.json()["state"] == "submitted"

def test_submit_timesheet_rate_limit_exceeded(
        auth_client, unique_week, exhaust_rate_limit):
    exhaust_rate_limit(auth_client, endpoint="/timesheets/submit")
    payload = {
        "week": unique_week,
        "days": {
            "mon": 8, "tue": 8, "wed": 8, "thu": 8, "fri": 8,
            "sat": 0, "sun": 0
        }
    }
    resp = auth_client.post("/timesheets/submit", json=payload)
    assert resp.status_code == 429, resp.text
    assert "retry-after" in resp.headers or "detail" in resp.json()
